import { Signal } from "@unbndl/html";
import { Source, SourceEffect } from "@unbndl/view";
import { Observer } from "./observer.ts";

export function fromService<T extends object>(
  target: HTMLElement,
  contextLabel: string
): Source<T> {
  return new FromService<T>(target, contextLabel);
}

class FromService<T extends object>
  implements Source<T>
{
  private client: HTMLElement;
  private observer: Observer<T>;

  constructor(
    client: HTMLElement,
    contextLabel: string
  ) {
    this.client = client;
    this.observer = new Observer<T>(contextLabel);
  }

  start(fn: SourceEffect<T>): Promise<Partial<T>> {
    // console.log(
    //   "🔭 Starting to observe service",
    //   this.observer
    // );
    return this.observer.observe(
      this.client,
      (s: Signal<T, keyof T>) => {
        fn(s.property, s.value);
      }
    );
  }
}
